const fs = require('fs');
const markdown = fs.readFileSync('/home/halei/.openclaw/workspace/Selector/SELECTION-METHOD-v5.0.md', 'utf8');

// Split into ~3000 char chunks to add as paragraphs
const chunkSize = 3000;
const pageBlockId = docId;

function addChunk(markdown, start, callback) {
  const end = Math.min(start + chunkSize, markdown.length);
  let chunk = markdown.substring(start, end);

  // If in middle of a line, find next newline
  if (end < markdown.length) {
    const nextNewline = markdown.indexOf('\n', end);
    if (nextNewline > end) {
      chunk = markdown.substring(start, nextNewline);
    }
  }

  const blockPayload = {
    children: [{
      block_type: 2,
      text: {
        elements: [{ text_run: { content: chunk } }],
        style: {}
      }
    }],
    index: 999 // append at end
  };

  const body = JSON.stringify(blockPayload);
  const options = {
    hostname: 'open.feishu.cn',
    path: '/open-apis/docx/v1/documents/' + docId + '/blocks/' + pageBlockId + '/children',
    method: 'POST',
    headers: { 
      'Content-Type': 'application/json', 
      'Content-Length': Buffer.byteLength(body), 
      'Authorization': 'Bearer ' + token 
    }
  };

  const req = https.request(options, (res) => {
    let data = '';
    res.on('data', d => data += d);
    res.on('end', () => {
      const result = JSON.parse(data);
      if (result.code === 0) {
        callback(null, end);
      } else {
        console.log('Error at', start, ':', result.code, result.msg);
        callback(result, start);
      }
    });
  });
  req.on('error', e => { console.error(e); callback(e, start); });
  req.write(body);
  req.end();
}

let pos = 0;
function addNext() {
  if (pos >= markdown.length) {
    console.log('DONE - all content added');
    return;
  }
  addChunk(markdown, pos, (err, newPos) => {
    pos = newPos;
    if (err) {
      // If error, skip ahead
      pos += chunkSize;
    }
    // Small delay to avoid rate limit
    setTimeout(addNext, 100);
  });
}

addNext();
